Host list (asset inventory):
```python
def get_host_list(session, base_url, tag_name=None):
    url = f'{base_url}/api/2.0/fo/asset/host/'
    params = {'action': 'list', 'details': 'All', 'truncation_limit': '0'}
    if tag_name:
        params['use_tags'] = '1'
        params['tag_set_include'] = tag_name
    resp = session.post(url, data=params, timeout=(10, 300))
    resp.raise_for_status()
    return ET.fromstring(resp.text).findall('.//HOST')
```

KnowledgeBase lookup (enrich QIDs with CVEs):
```python
def get_kb_entries(session, base_url, qids: list[str]):
    url = f'{base_url}/api/2.0/fo/knowledge_base/vuln/'
    params = {'action': 'list', 'ids': ','.join(qids), 'details': 'All'}
    resp = session.post(url, data=params, timeout=(10, 120))
    resp.raise_for_status()
    root = ET.fromstring(resp.text)
    return {v.findtext('QID'): v for v in root.findall('.//VULN')}
```
